                                "cdn":flashvars.cdn,
                                "startLagThreshold":flashvars.startLagThreshold,
                                "outBufferLagThreshold":flashvars.outBufferLagThreshold
                            }]
                        }
                    }
                },
                eventTracking: {
                    params: {
                        cdn: flashvars.cdn,
                        isp: flashvars.isp,
                        geo: flashvars.geo,
